// Cycle through the pin list one per run (no state file needed), then build
// the Buffer GraphQL createPost body. Buffer's new API lives at
// https://api.buffer.com and takes { query, variables }.
const data = $input.first().json;
const pins = (data && data.pins) || [];
if (!pins.length) { throw new Error('pins.json empty'); }

const store = $getWorkflowStaticData('global');
let idx = typeof store.idx === 'number' ? store.idx : 0;
if (idx >= pins.length) idx = 0;
const pin = pins[idx];
store.idx = idx + 1;

// Pinterest description = title + description + link (kept under ~480 chars).
// The article link goes in the text as a fallback destination; once the first
// post succeeds we can move it to the Pinterest destination-URL field.
const text = (pin.title + '\n\n' + pin.description + '\n\n' + pin.link).slice(0, 480);

// Paste your Pinterest channel id below (from buffer_get_channel.py). It is
// not secret. Do NOT use $env here — many n8n instances block env access.
const CHANNEL_ID = 'PASTE_YOUR_PINTEREST_CHANNEL_ID';

const query = 'mutation Create($input: CreatePostInput!) { createPost(input: $input) { __typename ... on PostActionSuccess { post { id } } ... on MutationError { message } } }';

const graphqlBody = {
  query,
  variables: {
    input: {
      text,
      channelId: CHANNEL_ID,
      schedulingType: 'automatic',
      mode: 'addToQueue',
      assets: [ { image: { url: pin.image } } ]
    }
  }
};

return [{ json: { graphqlBody, slug: pin.slug } }];
